def maxLength(arr):
    def bit(s):
        b = 0
        for c in s:
            if b & (1 << (ord(c)-97)): return 0
            b |= (1 << (ord(c)-97))
        return b
    dp = [0]; res = 0
    for s in arr:
        b = bit(s)
        if not b: continue
        for mask in dp[:]:
            if not (mask & b): dp.append(mask | b); res = max(res, bin(mask | b).count('1'))
    return res

